// Get all known installation names for the dropdown
export const BAH_INSTALLATIONS = Object.keys(INSTALLATION_MHA_MAP).sort();

// Get BAH rate for a given installation and pay grade
export function getBAHRate(installationName, payGrade, withDependents) {
  const mha = INSTALLATION_MHA_MAP[installationName];
  if (!mha) return null;
  const rates = MHA_RATES[mha];
  if (!rates) return null;
  const idx = BAH_PAY_GRADES.indexOf(payGrade);
  if (idx === -1) return null;
  return withDependents ? rates[idx][0] : rates[idx][1];
}

export function getMHAForInstallation(installationName) {
  return INSTALLATION_MHA_MAP[installationName] || null;
}

export function isOCONUS(installationName) {
  if (!installationName || typeof installationName !== 'string') return false;
  const oconusKeywords = ['Korea','Germany','Japan','Italy','Guam','Okinawa','Cuba','Bahrain','Kuwait','Qatar','Djibouti','Humphreys','Daegu','Yongsan','Ramstein','Kaiserslautern','Spangdahlem','Wiesbaden','Grafenwoehr','Vilseck','Baumholder','Ansbach','Stuttgart','Torii','Kadena','Misawa','Camp Zama','Yokosuka','Sasebo','Naples','Vicenza','Aviano','Sigonella','Rota','Moron','Incirlik','NSA Bahrain','Lemonnier','Iwakuni','Futenma','Butler','Guantanamo','Gtmo',
    // ── OCONUS keyword gaps (added). Each is either a distinct overseas base
    // name or a country/locality that cannot collide with a CONUS base name.
    // NOTE: deliberately NOT using bare 'England' — it would false-positive the
    // CONUS Coast Guard sectors 'USCG Sector Northern/Southeast New England'.
    // UK / RAF
    'RAF ','Lakenheath','Mildenhall','Croughton','Alconbury','Menwith Hill','United Kingdom',
    // Portugal / Azores
    'Lajes','Azores','Portugal',
    // Belgium (NATO)
    'Belgium','SHAPE','Chievres','Chièvres',
    // Poland
    'Poland',
    // Kosovo
    'Kosovo','Bondsteel',
    // Greenland
    'Greenland','Thule','Pituffik',
    // Indian Ocean
    'Diego Garcia',
    // Singapore
    'Singapore',
    // Norway
    'Norway','Stavanger',
    // Greece
    'Greece','Souda',
    // Netherlands
    'Netherlands','Brunssum',
    // Puerto Rico — a non-foreign OCONUS territory. Like Guam, PR members
    // receive OHA (not BAH); the 50 states + D.C. are the only BAH areas.
    // These installation tokens are unambiguous (no CONUS base collides).
    // Keeps this BAH-tab detector consistent with the data-driven
    // isOCONUSInstallation in App.jsx (PR entries carry country:'Puerto Rico').
    'Puerto Rico','Buchanan','San Juan','Borinquen'];
  return oconusKeywords.some(kw => installationName.includes(kw));
}

export function formatCurrencyBAH(amount) {
  if (amount === null || amount === undefined) return '—';
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(amount);
}

// MHA keys whose rates are best-effort 2026 estimates, NOT pulled from an
// official DTMO published table. Sourced from the "Added 2026" comment block
// in MHA_RATES above. The BAH calculator UI shows a verification pill when
// the resolved MHA for the selected installation is in this set.
// Remove a key from this set once its rates have been confirmed against the
// official DTMO BAH Rate Lookup — leave the row in MHA_RATES untouched.
export const ESTIMATED_MHA_KEYS = new Set([
  // Only MHAs WITHOUT an authoritative row in the published DTMO 2026 CONUS
  // table remain estimates. Every other MHA was reconciled to the official
  // 2026 rates (see scripts/bah-reconcile/).
  'San Juan, PR',        // Puerto Rico not in the published CONUS BAH table
  'Bowie County, TX',    // Red River Army Depot / Texarkana - no DTMO MHA match
]);

export function isEstimatedMHA(mhaKey) {
  return ESTIMATED_MHA_KEYS.has(mhaKey);
}

